// ============================================================================
// VCM Startup-Simulation — Spieldaten
// ----------------------------------------------------------------------------
// Alle Inhalte des Spiels (Szenario, Runden/Phasen, Entscheidungen, Glücks-
// Events, Founder-Typen) leben hier. Reines Daten-Modul ohne UI — so kann der
// Venture Club die Fragen pflegen, ohne Logik oder Layout anzufassen.
//
// Design-Prinzipien (aus der Planung):
//  - KEIN perfekter Durchlauf: jede Option hat Trade-offs.
//  - Schlechte Entscheidungen dürfen NEGATIVE Punkte geben.
//  - Pro Phase wird EINE Frage zufällig aus einem Pool gezogen → bleibt frisch.
//  - Glück ist Bestandteil, aber klein gegenüber Entscheidungen.
// ============================================================================

export type StatKey = "growth" | "innovation" | "community" | "impact";

/** Die vier bewerteten Säulen + Cash als Überlebens-Ressource (Runway). */
export interface Stats {
  growth: number;
  innovation: number;
  community: number;
  impact: number;
  cash: number;
}

export interface Option {
  id: string;
  label: string;
  /** Veränderungen der Werte (Trade-offs). Nicht genannte Werte = 0. */
  effects: Partial<Stats>;
  /** Punkte für diese Entscheidung (darf negativ sein). */
  points: number;
  /** Kurze Lern-/Konsequenz-Erklärung — der "Aha"-Moment. */
  outcome: string;
}

export interface Scenario {
  id: string;
  /** 1-basierte Phasen-Nummer (Bezug zu PHASES). */
  phase: number;
  title: string;
  situation: string;
  options: Option[];
}

export interface LuckEvent {
  id: string;
  title: string;
  text: string;
  effects: Partial<Stats>;
}

export interface FounderType {
  key: StatKey | "balanced";
  name: string;
  tagline: string;
  description: string;
  emoji: string;
}

// ---------------------------------------------------------------------------
// Szenario-Rahmen — wird zu Beginn vorgestellt.
// ---------------------------------------------------------------------------
export const SCENARIO_INTRO = {
  startup: "Loop",
  oneLiner: "Das Mehrweg-Pfand-Netzwerk für Münster",
  pitch:
    "Ihr gründet «Loop» — ein Pfandsystem für Mehrwegbecher und -boxen. " +
    "Cafés, Mensen und Foodtrucks geben Essen & Getränke in euren Behältern aus, " +
    "Studierende geben sie an smarten Rückgabe-Stationen zurück. Weniger Müll, " +
    "ein cooles App-Erlebnis, eine echte Community.",
  conditions: [
    "Team: du + 1 unentschlossene:r Mitgründer:in",
    "Kapital: 100 (Runway-Wochen)",
    "Markt: Münster — Fahrrad-Stadt, viele Studierende, nachhaltigkeitsaffin",
    "Wettbewerb: 1 großer nationaler Anbieter, noch nicht vor Ort",
  ],
};

/** Startwerte. Cash = "Runway" (Überlebens-Ressource). */
export const INITIAL_STATS: Stats = {
  growth: 20,
  innovation: 20,
  community: 20,
  impact: 20,
  cash: 100,
};

// ---------------------------------------------------------------------------
// Phasen der Gründungsreise (Bezug zu Founders Map "Gründungsreise").
// ---------------------------------------------------------------------------
export const PHASES = [
  { n: 1, name: "Die Idee", intro: "Aus einer Idee wird ein Plan. Erste Weichen stellen." },
  { n: 2, name: "Das Produkt", intro: "Vom Konzept zum ersten echten Produkt (MVP)." },
  { n: 3, name: "Die Finanzierung", intro: "Geld bewegt — aber zu welchem Preis?" },
  { n: 4, name: "Das Wachstum", intro: "Aus einem Pilot wird ein Unternehmen." },
  { n: 5, name: "Die Bewährungsprobe", intro: "Jedes Startup wird einmal richtig getestet." },
] as const;

// ---------------------------------------------------------------------------
// Szenario-Pool. Pro Phase ≥2 Szenarien → eines wird zufällig gezogen.
// effects-Werte sind bewusst so gesetzt, dass es nie eine dominante Option gibt.
// ---------------------------------------------------------------------------
export const SCENARIOS: Scenario[] = [
  // ===== Phase 1 — Die Idee =====
  {
    id: "p1-cofounder",
    phase: 1,
