  // ===== Phase 2 — Das Produkt =====
  {
    id: "p2-mvp",
    phase: 2,
    title: "Wie viel Produkt zum Start?",
    situation:
      "Der Launch naht. Wie gut muss das erste Produkt wirklich sein?",
    options: [
