  growth: 20,
  innovation: 20,
  community: 20,
  impact: 20,
  cash: 100,
};

// ---------------------------------------------------------------------------
// Phasen der Gründungsreise (Bezug zu Founders Map "Gründungsreise").
// ---------------------------------------------------------------------------
