"use client";

import { motion } from "framer-motion";
import { TrendingUp, Lightbulb, Users, Globe, Wallet } from "lucide-react";
import type { Stats, StatKey } from "@/lib/gameData";

const META: Record<
  StatKey | "cash",
  { label: string; icon: React.ElementType; color: string }
> = {
  growth: { label: "Growth", icon: TrendingUp, color: "#ff7a1a" },
  innovation: { label: "Innovation", icon: Lightbulb, color: "#ffc857" },
  community: { label: "Community", icon: Users, color: "#5ec8ff" },
  impact: { label: "Impact", icon: Globe, color: "#4ade80" },
  cash: { label: "Runway", icon: Wallet, color: "#f87171" },
};

/** Skala: Säulen ~0–80 typisch, Cash 0–140. Auf 0–100 % normalisiert. */
const MAX: Record<StatKey | "cash", number> = {
  growth: 80,
  innovation: 80,
  community: 80,
  impact: 80,
  cash: 140,
};

function Bar({ k, value }: { k: StatKey | "cash"; value: number }) {
  const { label, icon: Icon, color } = META[k];
  const pct = Math.min(100, Math.max(0, (value / MAX[k]) * 100));
  return (
    <div className="flex flex-col gap-1">
      <div className="flex items-center justify-between text-[11px]">
        <span className="flex items-center gap-1" style={{ color }}>
          <Icon size={13} strokeWidth={2.4} />
          <span style={{ color: "var(--muted)" }}>{label}</span>
        </span>
        <span style={{ color: "var(--foreground)" }} className="font-semibold tabular-nums">
          {Math.round(value)}
        </span>
      </div>
      <div
        className="h-1.5 w-full overflow-hidden rounded-full"
        style={{ background: "var(--surface-3)" }}
      >
        <motion.div
          className="h-full rounded-full"
          style={{ background: color }}
          initial={false}
          animate={{ width: `${pct}%` }}
          transition={{ duration: 0.6, ease: [0.22, 1, 0.36, 1] }}
        />
      </div>
    </div>
  );
}

export default function StatBar({ stats }: { stats: Stats }) {
  return (
    <div className="grid grid-cols-2 gap-x-4 gap-y-2.5">
      <Bar k="growth" value={stats.growth} />
      <Bar k="innovation" value={stats.innovation} />
      <Bar k="community" value={stats.community} />
      <Bar k="impact" value={stats.impact} />
      <div className="col-span-2 mt-0.5">
        <Bar k="cash" value={stats.cash} />
      </div>
    </div>
  );
}

